prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?parallelGw ?gwName ?modelId WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?modelId .
  FILTER(?modelId = "0b21c69687b64d8886fb7cc5dc56ff6c")
  ?model tai:belongsTo ?org .
  ?def tai:belongsTo ?model .
  ?def bboExt:isClosed ?dummy .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?def .
  ?parallelGw a bboExt:ParallelGateway ;
              tai:belongsTo ?choreo .
  OPTIONAL { ?parallelGw bbo:name ?gwName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelId ?kind ?gw ?name ?choreo WHERE {
  VALUES ?kind { "ParallelGateway" "EventBasedGateway" "ExclusiveGateway" }

  ?model a bboExt:Model ;
         tai:normalizedId ?modelId .
  FILTER(?modelId = "0b21c69687b64d8886fb7cc5dc56ff6c")

  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?def .

  {
    ?gw a bboExt:ParallelGateway .
    BIND("ParallelGateway" AS ?kind)
  }
  UNION
  {
    ?gw a bboExt:EventBasedGateway .
    BIND("EventBasedGateway" AS ?kind)
  }
  UNION
  {
    ?gw a bboExt:ExclusiveGateway .
    BIND("ExclusiveGateway" AS ?kind)
  }

  ?gw tai:belongsTo ?choreo .
  OPTIONAL { ?gw bbo:name ?name . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?normId ?origId ?org WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?normId .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  FILTER(?normId = "0b21c69687b64d8886fb7cc5dc56ff6c" || ?origId = "0b21c69687b64d8886fb7cc5dc56ff6c")
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?gwType ?gw ?name WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?normId .
  FILTER(?normId = "sid_32ebd244_789a_4034_845b_7909f514afae")

  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  {
    ?gw a bboExt:ParallelGateway .
    BIND("ParallelGateway" AS ?gwType)
  }
  UNION
  {
    ?gw a bboExt:EventBasedGateway .
    BIND("EventBasedGateway" AS ?gwType)
  }

  FILTER(?gwType = "ParallelGateway" || ?gwType = "EventBasedGateway")
  ?gw tai:belongsTo ?choreo .
  OPTIONAL { ?gw bbo:name ?name . }
}
LIMIT 25
